// Defines the enumerated values to specify the nature of a location identifier.
type CommodityLocationIdentifierTypeEnum string

const (
	// The physical or virtual point at which the commodity will be delivered.
	CommodityLocationIdentifierTypeEnumDeliveryPoint CommodityLocationIdentifierTypeEnum = "DeliveryPoint"
	// The physical or virtual point at which the commodity enters a transportation system.
	CommodityLocationIdentifierTypeEnumEntryPoint CommodityLocationIdentifierTypeEnum = "EntryPoint"
	// Identification of the border(s) or border point(s) of a transportation contract.
	CommodityLocationIdentifierTypeEnumInterconnectionPoint CommodityLocationIdentifierTypeEnum = "InterconnectionPoint"
	// The physical or virtual point at which the commodity is withdrawn from a transportation system.
	CommodityLocationIdentifierTypeEnumWithdrawalPoint CommodityLocationIdentifierTypeEnum = "WithdrawalPoint"
	// The zone covering potential delivery points for the commodity
	CommodityLocationIdentifierTypeEnumDeliveryZone CommodityLocationIdentifierTypeEnum = "DeliveryZone"
	// The hub code of the buyer.
	CommodityLocationIdentifierTypeEnumBuyerHub CommodityLocationIdentifierTypeEnum = "BuyerHub"
	// The hub code of the seller.
	CommodityLocationIdentifierTypeEnumSellerHub CommodityLocationIdentifierTypeEnum = "SellerHub"
)
